/**
 * Upcoming page — timeline + multi-select filters + search.
 * Reads window.UPCOMING_RELEASES (generated by scripts/build_upcoming.py or hand-curated).
 * Supports both new schema (id, releaseDate ISO, source, sourceReason, posterUrl, …)
 * and legacy schema (genre string, imdbRating, type "TV series", free-form releaseDate).
 */
(function (global) {
  'use strict';

  var raw = global.UPCOMING_RELEASES;
  var grid = document.getElementById('upcoming-grid');
  var filterBar = document.getElementById('upcoming-filters');
  var searchInput = document.getElementById('upcoming-search');
  var countEl = document.getElementById('upcoming-count');
  if (!grid) return;

  if (!raw || !raw.length) {
    grid.innerHTML =
      '<p class="section-lede">No upcoming releases yet. Run <code>python scripts/build_upcoming.py</code> to regenerate.</p>';
    if (countEl) countEl.textContent = '';
    return;
  }

  // ------------------------------------------------------------------
  // Normalization: legacy + new schema → unified internal record
  // ------------------------------------------------------------------

  function esc(s) {
    return String(s == null ? '' : s)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  function normalizeType(t) {
    var v = (t || '').toString().toLowerCase();
    if (v === 'movie' || v === 'film') return 'movie';
    if (v === 'tv' || v === 'tv series' || v === 'tv mini series' || v === 'series') return 'tv';
    return v || 'movie';
  }

  function toIsoDate(item) {
    if (item.releaseDate && /^\d{4}(-\d{2}(-\d{2})?)?$/.test(item.releaseDate)) {
      var s = item.releaseDate;
      if (s.length === 4) return s + '-12-31';
      if (s.length === 7) return s + '-28';
      return s;
    }
    var str = (item.releaseDate || '').toString();
    var p = Date.parse(str);
    if (!isNaN(p)) {
      var d = new Date(p);
      var pad = function (n) {
        return (n < 10 ? '0' : '') + n;
      };
      return d.getFullYear() + '-' + pad(d.getMonth() + 1) + '-' + pad(d.getDate());
    }
    var yearMatch = str.match(/(20\d{2}|21\d{2})/);
    if (yearMatch) {
      var y = yearMatch[1];
      var lower = str.toLowerCase();
      if (/spring/.test(lower)) return y + '-04-15';
      if (/summer/.test(lower)) return y + '-07-15';
      if (/fall|autumn/.test(lower)) return y + '-10-15';
      if (/winter/.test(lower)) return y + '-01-15';
      return y + '-12-31';
    }
    return '9999-12-31';
  }

  function displayDate(item, iso) {
    if (item.releaseDateDisplay) return item.releaseDateDisplay;
    if (item.releaseDate && typeof item.releaseDate === 'string' && !/^\d{4}-\d{2}-\d{2}$/.test(item.releaseDate)) {
      return item.releaseDate;
    }
    if (iso && iso !== '9999-12-31') {
      try {
        var d = new Date(iso + 'T00:00:00');
        return d.toLocaleDateString(undefined, { month: 'long', day: 'numeric', year: 'numeric' });
      } catch (e) {
        /* noop */
      }
    }
    return 'Date TBD';
  }

  function toGenres(item) {
    if (Array.isArray(item.genres)) return item.genres.filter(Boolean);
    if (typeof item.genre === 'string') {
      return item.genre.split(',').map(function (g) {
        return g.trim();
      }).filter(Boolean);
    }
    return [];
  }

  function toTags(item) {
    return Array.isArray(item.tags) ? item.tags.filter(Boolean) : [];
  }

  /** Lowercase alnum tokens for comparing a tag chip to TMDB-style genre strings. */
  function normalizeTagForMatch(s) {
    return String(s || '')
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
  }

  /**
   * True if this tag only repeats wording already shown in the foot genre row
   * (exact genre match or the tag equals a whole word inside a compound genre).
   */
  function isTagRedundantWithGenres(tag, genres) {
    var t = normalizeTagForMatch(tag);
    if (!t) return true;
    for (var i = 0; i < genres.length; i++) {
      var g = normalizeTagForMatch(genres[i]);
      if (!g) continue;
      if (g === t) return true;
      var parts = g.split(' ');
      for (var j = 0; j < parts.length; j++) {
        if (parts[j] && parts[j] === t) return true;
      }
    }
    return false;
  }

  /** Drop genre-duplicating chips; keep editorial cues (Returning, Korean, Satire, names, …). */
  function tagsMinusGenreOverlap(tags, genres) {
    if (!tags.length || !genres.length) return tags;
    return tags.filter(function (tag) {
      return !isTagRedundantWithGenres(tag, genres);
    });
  }

  function normalize(item) {
    var type = normalizeType(item.type);
    var iso = toIsoDate(item);
    var record = {
      id: item.id || item.imdbUrl || item.title,
      title: item.title || '',
      type: type,
      releaseDateIso: iso,
      releaseDateDisplay: displayDate(item, iso),
      status: item.status || '',
      genres: toGenres(item),
      country: item.country || '',
      posterUrl: item.posterUrl || '',
      imdbUrl: item.imdbUrl || '',
      source: item.source || (item._source || 'editorial'),
      sourceReason: item.sourceReason || '',
      showTitle: item.showTitle || '',
      seasonNumber: item.seasonNumber == null ? null : item.seasonNumber,
      episodeCount: item.episodeCount == null ? null : item.episodeCount,
      description: item.description || '',
      tags: toTags(item),
      platform: item.platform || '',
    };
    record._search = [
      record.title,
      record.sourceReason,
      record.showTitle,
      record.description,
      record.genres.join(' '),
      record.tags.join(' '),
      record.country,
    ]
      .join(' ')
      .toLowerCase();
    return record;
  }

  var items = raw.map(normalize);

  // ------------------------------------------------------------------
  // URL hash state
  // ------------------------------------------------------------------

  var state = {
    q: '',
    type: 'all', // all | movie | tv
    sources: {}, // director, seen-tv, editorial
    statuses: {}, // free-form status strings
    genres: {}, // free-form
    countries: {}, // free-form
  };

  function readHash() {
    var h = (location.hash || '').replace(/^#/, '');
    if (!h) return;
    h.split('&').forEach(function (part) {
      var eq = part.indexOf('=');
      if (eq < 0) return;
      var k = decodeURIComponent(part.slice(0, eq));
      var v = decodeURIComponent(part.slice(eq + 1));
      if (k === 'q') state.q = v;
      else if (k === 'type') state.type = v || 'all';
      else if (k === 'source') v.split(',').filter(Boolean).forEach(function (x) { state.sources[x] = true; });
      else if (k === 'status') v.split(',').filter(Boolean).forEach(function (x) { state.statuses[x] = true; });
      else if (k === 'genre') v.split(',').filter(Boolean).forEach(function (x) { state.genres[x] = true; });
      else if (k === 'country') v.split(',').filter(Boolean).forEach(function (x) { state.countries[x] = true; });
    });
  }

  function writeHash() {
    var parts = [];
    if (state.q) parts.push('q=' + encodeURIComponent(state.q));
    if (state.type && state.type !== 'all') parts.push('type=' + encodeURIComponent(state.type));
    var setToList = function (m) {
      return Object.keys(m).filter(function (k) { return m[k]; });
    };
    var s = setToList(state.sources);
    if (s.length) parts.push('source=' + encodeURIComponent(s.join(',')));
    var st = setToList(state.statuses);
    if (st.length) parts.push('status=' + encodeURIComponent(st.join(',')));
    var g = setToList(state.genres);
    if (g.length) parts.push('genre=' + encodeURIComponent(g.join(',')));
    var c = setToList(state.countries);
    if (c.length) parts.push('country=' + encodeURIComponent(c.join(',')));
    var newHash = parts.length ? '#' + parts.join('&') : '';
    if (newHash !== location.hash) {
      history.replaceState(null, '', location.pathname + location.search + newHash);
    }
  }

  readHash();

  // ------------------------------------------------------------------
  // Filter options (derived)
  // ------------------------------------------------------------------

  function uniqueSortedValues(key, extract) {
    var set = {};
    items.forEach(function (it) {
      var v = extract(it);
      if (Array.isArray(v)) v.forEach(function (x) { if (x) set[x] = true; });
      else if (v) set[v] = true;
    });
    return Object.keys(set).sort();
  }

  var SOURCE_LABELS = {
    'director': 'Favorite directors',
    'seen-tv': 'Returning shows',
    'editorial': "Editor's picks",
  };
  var allSources = uniqueSortedValues('source', function (it) { return it.source; });
  var allStatuses = uniqueSortedValues('status', function (it) { return it.status; });
  var allGenres = uniqueSortedValues('genres', function (it) { return it.genres; });
  var allCountries = uniqueSortedValues('country', function (it) { return it.country; });

  // ------------------------------------------------------------------
  // Timeline bucketing
  // ------------------------------------------------------------------

  function startOfMonth(d) {
    return new Date(d.getFullYear(), d.getMonth(), 1);
  }
  function addMonths(d, n) {
    return new Date(d.getFullYear(), d.getMonth() + n, 1);
  }

  var MONTHS_SHORT = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

  // Bucket fields:
  //   key / label / order — timeline grouping
  //   granularity — 'month' (bucket header already says the month) vs 'broad' (header says a range or year)
  //                 drives what we show on the per-card date badge.
  function bucketFor(iso, now) {
    if (iso === '9999-12-31') return { key: 'zz-tbd', label: 'Date TBD', order: 999999, granularity: 'tbd' };
    var d = new Date(iso + 'T00:00:00');
    if (isNaN(d.getTime())) return { key: 'zz-tbd', label: 'Date TBD', order: 999999, granularity: 'tbd' };
    var monthStart = startOfMonth(now);
    var daysAgo = Math.floor((monthStart - d) / 86400000);
    var thisMonthEnd = addMonths(monthStart, 1);
    var threeMonthsOut = addMonths(monthStart, 4);
    var endOfThisYear = new Date(now.getFullYear() + 1, 0, 1);

    if (d < monthStart && daysAgo <= 45) {
      return { key: 'a-recent', label: 'Recently released', order: 0, granularity: 'broad' };
    }
    if (d < monthStart) {
      return { key: 'a-older', label: 'Earlier', order: 1, granularity: 'broad' };
    }
    if (d < thisMonthEnd) {
      var thisMonthLabel = d.toLocaleDateString(undefined, { month: 'long', year: 'numeric' });
      return { key: 'b-this-month', label: 'This month · ' + thisMonthLabel, order: 10, granularity: 'month' };
    }
    if (d < threeMonthsOut) {
      var monthLabel = d.toLocaleDateString(undefined, { month: 'long', year: 'numeric' });
      var ord = 20 + (d.getFullYear() - now.getFullYear()) * 12 + d.getMonth();
      return { key: 'c-' + d.getFullYear() + '-' + (d.getMonth() + 1), label: monthLabel, order: ord, granularity: 'month' };
    }
    if (d < endOfThisYear) {
      return { key: 'd-later-this-year', label: 'Later this year', order: 100, granularity: 'broad' };
    }
    var year = d.getFullYear();
    return { key: 'e-' + year, label: String(year), order: 200 + year, granularity: 'broad' };
  }

  // What to show on the card's day badge given the bucket granularity.
  // Returns { primary, secondary } — e.g. { primary: '5', secondary: 'Fri' } or { primary: 'Jun', secondary: '5' }.
  function cardDateBadge(item, bucket) {
    var iso = item.releaseDateIso;
    if (iso === '9999-12-31' || bucket.granularity === 'tbd') {
      // Legacy free-form release strings like "Fall 2026" — surface them here.
      var raw = item.releaseDateDisplay || '';
      if (raw && raw !== 'Date TBD') {
        return { primary: raw.length > 8 ? raw.slice(0, 8) : raw, secondary: '' };
      }
      return { primary: 'TBD', secondary: '' };
    }
    var d = new Date(iso + 'T00:00:00');
    if (isNaN(d.getTime())) return { primary: 'TBD', secondary: '' };
    var day = d.getDate();
    if (bucket.granularity === 'month') {
      var dow = d.toLocaleDateString(undefined, { weekday: 'short' });
      return { primary: String(day), secondary: dow };
    }
    return { primary: MONTHS_SHORT[d.getMonth()], secondary: String(day) };
  }

  // ------------------------------------------------------------------
  // Filtering
  // ------------------------------------------------------------------

  function matches(item) {
    if (state.type !== 'all' && item.type !== state.type) return false;
    var sKeys = Object.keys(state.sources).filter(function (k) { return state.sources[k]; });
    if (sKeys.length && sKeys.indexOf(item.source) === -1) return false;
    var stKeys = Object.keys(state.statuses).filter(function (k) { return state.statuses[k]; });
    if (stKeys.length && stKeys.indexOf(item.status) === -1) return false;
    var gKeys = Object.keys(state.genres).filter(function (k) { return state.genres[k]; });
    if (gKeys.length && !gKeys.some(function (g) { return item.genres.indexOf(g) !== -1; })) return false;
    var cKeys = Object.keys(state.countries).filter(function (k) { return state.countries[k]; });
    if (cKeys.length && cKeys.indexOf(item.country) === -1) return false;
    if (state.q) {
      var q = state.q.toLowerCase().trim();
      if (q && item._search.indexOf(q) === -1) return false;
    }
    return true;
  }

  // ------------------------------------------------------------------
  // Rendering
  // ------------------------------------------------------------------

  function shortStatus(status) {
    if (!status) return '';
    var s = String(status).trim();
    if (/^returning/i.test(s)) return 'Returning';
    if (/^in production/i.test(s)) return 'In production';
    if (/^post production/i.test(s)) return 'Post-production';
    if (/^planned/i.test(s)) return 'Planned';
    if (/^released/i.test(s)) return '';
    if (/^ended$/i.test(s)) return '';
    return s;
  }

  function renderCard(item, bucket) {
    var titleLink = item.imdbUrl
      ? '<a href="' + esc(item.imdbUrl) + '" target="_blank" rel="noopener noreferrer">' + esc(item.title) + '</a>'
      : esc(item.title);

    var typeBadge = '<span class="timeline-card__type" data-type="' +
      (item.type === 'movie' ? 'movie' : 'tv') + '">' +
      (item.type === 'movie' ? 'Movie' : 'TV') + '</span>';

    var badge = cardDateBadge(item, bucket);
    var dateBadge =
      '<div class="timeline-card__date" aria-label="' + esc(item.releaseDateDisplay) + '">' +
      '<span class="timeline-card__date-primary">' + esc(badge.primary) + '</span>' +
      (badge.secondary ? '<span class="timeline-card__date-secondary">' + esc(badge.secondary) + '</span>' : '') +
      '</div>';

    var poster = item.posterUrl
      ? '<img class="timeline-card__poster" src="' + esc(item.posterUrl) + '" alt="" loading="lazy" decoding="async" width="72" height="108">'
      : '';

    var reason = item.sourceReason
      ? '<p class="timeline-card__reason">' + esc(item.sourceReason) + '</p>'
      : '';

    var description = item.description
      ? '<p class="timeline-card__desc">' + esc(item.description) + '</p>'
      : '';

    // Inline secondary meta: country · platform · status as plain muted text.
    var inlineBits = [];
    if (item.country) inlineBits.push('<span>' + esc(item.country) + '</span>');
    if (item.platform) inlineBits.push('<span class="timeline-card__platform">' + esc(item.platform) + '</span>');
    var statusShort = shortStatus(item.status);
    if (statusShort) inlineBits.push('<span class="timeline-card__status">' + esc(statusShort) + '</span>');
    var inlineMeta = inlineBits.length
      ? '<div class="timeline-card__inline-meta">' + inlineBits.join('<span aria-hidden="true" class="timeline-card__sep">·</span>') + '</div>'
      : '';

    var tagChips = tagsMinusGenreOverlap(item.tags, item.genres);
    var tagsHtml = tagChips.length
      ? '<div class="upcoming-tags">' + tagChips.map(function (t) {
          return '<span class="tag-inline">' + esc(t) + '</span>';
        }).join('') + '</div>'
      : '';

    var genresHtml = item.genres.length
      ? '<div class="timeline-card__genres">' + item.genres.slice(0, 4).map(esc).join(' · ') + '</div>'
      : '';

    var imdbLink = item.imdbUrl
      ? '<a href="' + esc(item.imdbUrl) + '" target="_blank" rel="noopener noreferrer" class="timeline-card__imdb">IMDb</a>'
      : '';

    return (
      '<article class="timeline-card">' +
      dateBadge +
      '<div class="timeline-card__body">' +
      '<h3 class="timeline-card__title">' + titleLink + typeBadge + '</h3>' +
      reason +
      description +
      inlineMeta +
      tagsHtml +
      ((genresHtml || imdbLink)
        ? '<div class="timeline-card__foot">' + genresHtml + '<div class="timeline-card__ratings">' + imdbLink + '</div></div>'
        : '') +
      '</div>' +
      poster +
      '</article>'
    );
  }

  function render() {
    var matched = items.filter(matches);
    if (countEl) {
      countEl.textContent = 'Showing ' + matched.length + ' of ' + items.length;
    }
    if (!matched.length) {
      grid.innerHTML = '<p class="section-lede">Nothing matches these filters. <a href="#" class="upcoming-clear-inline">Clear filters</a>.</p>';
      return;
    }

    matched.sort(function (a, b) {
      if (a.releaseDateIso < b.releaseDateIso) return -1;
      if (a.releaseDateIso > b.releaseDateIso) return 1;
      return a.title.localeCompare(b.title);
    });

    var now = new Date();
    var buckets = {};
    matched.forEach(function (it) {
      var b = bucketFor(it.releaseDateIso, now);
      if (!buckets[b.key]) buckets[b.key] = { label: b.label, order: b.order, items: [] };
      buckets[b.key].items.push(it);
    });

    var keys = Object.keys(buckets).sort(function (a, b) {
      return buckets[a].order - buckets[b].order;
    });

    var html = '<div class="timeline" role="feed">';
    keys.forEach(function (k) {
      var b = buckets[k];
      var anchor = 'tl-' + k.replace(/[^a-z0-9]+/gi, '-');
      html +=
        '<section class="timeline-year-block" aria-labelledby="' + anchor + '">' +
        '<h3 class="timeline-year-label" id="' + anchor + '">' + esc(b.label) + ' <span class="timeline-year-count">' + b.items.length + '</span></h3>' +
        '<div class="timeline-rail">' +
        b.items.map(function (it) { return renderCard(it, b); }).join('') +
        '</div>' +
        '</section>';
    });
    html += '</div>';
    grid.innerHTML = html;
  }

  // ------------------------------------------------------------------
  // Filter bar rendering
  // ------------------------------------------------------------------

  function chipButton(label, attrs, active) {
    return (
      '<button type="button" class="filter-chip' + (active ? ' active' : '') + '"' +
      Object.keys(attrs).map(function (k) {
        return ' ' + k + '="' + esc(attrs[k]) + '"';
      }).join('') +
      ' aria-pressed="' + (active ? 'true' : 'false') + '">' +
      esc(label) +
      '</button>'
    );
  }

  // A filter group: label on the left, chips inside a horizontal track.
  // Groups with > SCROLL_THRESHOLD chips become horizontally scrollable so the
  // filter bar never takes more than ~2 rows of vertical space.
  var SCROLL_THRESHOLD = 6;

  function renderFilterGroup(labelText, chipsHtml, chipCount) {
    var scroll = chipCount > SCROLL_THRESHOLD;
    var groupClass = 'filter-group' + (scroll ? ' filter-group--scroll' : '');
    return (
      '<div class="' + groupClass + '">' +
      '<span class="filter-group__label">' + esc(labelText) + '</span>' +
      '<div class="filter-group__track">' + chipsHtml + '</div>' +
      '</div>'
    );
  }

  function renderFilterBar() {
    if (!filterBar) return;
    var segments = [];

    var typeChips = ['all', 'movie', 'tv'].map(function (t) {
      var label = t === 'all' ? 'All' : t === 'movie' ? 'Movies' : 'TV';
      return chipButton(label, { 'data-filter': 'type', 'data-value': t }, state.type === t);
    }).join('');
    segments.push(renderFilterGroup('Type', typeChips, 3));

    if (allSources.length > 1) {
      var srcChips = allSources.map(function (s) {
        var label = SOURCE_LABELS[s] || s;
        return chipButton(label, { 'data-filter': 'source', 'data-value': s }, !!state.sources[s]);
      }).join('');
      segments.push(renderFilterGroup('Source', srcChips, allSources.length));
    }

    if (allStatuses.length > 1) {
      var stChips = allStatuses.map(function (s) {
        return chipButton(s, { 'data-filter': 'status', 'data-value': s }, !!state.statuses[s]);
      }).join('');
      segments.push(renderFilterGroup('Status', stChips, allStatuses.length));
    }

    if (allGenres.length > 1) {
      // Sort active genres first so selections stay visible when the row is scrolled back to the left.
      var sortedGenres = allGenres.slice().sort(function (a, b) {
        var aa = state.genres[a] ? 0 : 1;
        var bb = state.genres[b] ? 0 : 1;
        if (aa !== bb) return aa - bb;
        return a.localeCompare(b);
      });
      var gChips = sortedGenres.map(function (g) {
        return chipButton(g, { 'data-filter': 'genre', 'data-value': g }, !!state.genres[g]);
      }).join('');
      segments.push(renderFilterGroup('Genre', gChips, sortedGenres.length));
    }

    if (allCountries.length > 1) {
      var sortedCountries = allCountries.slice().sort(function (a, b) {
        var aa = state.countries[a] ? 0 : 1;
        var bb = state.countries[b] ? 0 : 1;
        if (aa !== bb) return aa - bb;
        return a.localeCompare(b);
      });
      var cChips = sortedCountries.map(function (c) {
        return chipButton(c, { 'data-filter': 'country', 'data-value': c }, !!state.countries[c]);
      }).join('');
      segments.push(renderFilterGroup('Country', cChips, sortedCountries.length));
    }

    var hasAnyActive = (
      state.type !== 'all' ||
      Object.keys(state.sources).length ||
      Object.keys(state.statuses).length ||
      Object.keys(state.genres).length ||
      Object.keys(state.countries).length ||
      state.q
    );
    if (hasAnyActive) {
      segments.push('<button type="button" class="filter-clear" id="upcoming-clear">Clear filters</button>');
    }

    filterBar.innerHTML = segments.join('');
  }

  // ------------------------------------------------------------------
  // Events
  // ------------------------------------------------------------------

  function onFilterClick(e) {
    var btn = e.target.closest('.filter-chip');
    if (!btn) {
      if (e.target && e.target.id === 'upcoming-clear') {
        state.q = '';
        state.type = 'all';
        state.sources = {};
        state.statuses = {};
        state.genres = {};
        state.countries = {};
        if (searchInput) searchInput.value = '';
        writeHash();
        renderFilterBar();
        render();
      }
      return;
    }
    var filter = btn.getAttribute('data-filter');
    var value = btn.getAttribute('data-value');
    if (filter === 'type') {
      state.type = value;
    } else {
      var map = filter === 'source' ? state.sources
        : filter === 'status' ? state.statuses
        : filter === 'genre' ? state.genres
        : filter === 'country' ? state.countries
        : null;
      if (!map) return;
      if (map[value]) delete map[value];
      else map[value] = true;
    }
    writeHash();
    renderFilterBar();
    render();
  }

  if (filterBar) filterBar.addEventListener('click', onFilterClick);

  if (grid) {
    grid.addEventListener('click', function (e) {
      var a = e.target.closest('.upcoming-clear-inline');
      if (!a) return;
      e.preventDefault();
      state.q = '';
      state.type = 'all';
      state.sources = {};
      state.statuses = {};
      state.genres = {};
      state.countries = {};
      if (searchInput) searchInput.value = '';
      writeHash();
      renderFilterBar();
      render();
    });
  }

  var searchTimer = null;
  if (searchInput) {
    searchInput.value = state.q;
    searchInput.addEventListener('input', function () {
      clearTimeout(searchTimer);
      var v = searchInput.value;
      searchTimer = setTimeout(function () {
        state.q = v;
        writeHash();
        renderFilterBar();
        render();
      }, 150);
    });
  }

  // ------------------------------------------------------------------
  // Boot
  // ------------------------------------------------------------------

  renderFilterBar();
  render();

  var observer = new IntersectionObserver(
    function (entries) {
      entries.forEach(function (e) {
        if (e.isIntersecting) e.target.classList.add('visible');
      });
    },
    { threshold: 0.1 }
  );
  document.querySelectorAll('.fade-in').forEach(function (el) {
    observer.observe(el);
  });
})(typeof window !== 'undefined' ? window : globalThis);
